const AUTOMATED_JUL_07_2026_HARTA_ADDITIONAL_RECORDS =
  AUTOMATED_JUL_07_2026_HARTA_ADDITIONAL_ROWS.map(([
    name,
    county,
    sourceRole,
    sourceInstitution,
    dnaId,
    sentenceMonths,
    suspended,
    convictionYear,
    convictionDate,
    euFunds,
  ]) => ({
    name,
    party: 'Independent',
    position:
      sourceInstitution === 'Nu este cazul'
        ? sourceRole
        : `${sourceRole} in ${sourceInstitution}`,
    position_type: 'other',
    geography: {
      county,
      basis: 'case_location',
      note:
        `Registrul Harta coruptiei localizeaza condamnarea in judetul ${county}; functia consemnata era ${sourceRole}` +
        (sourceInstitution === 'Nu este cazul' ? '.' : ` in ${sourceInstitution}.`),
    },
    crime: euFunds
      ? 'Fapte de coruptie legate de fonduri europene'
      : 'Fapte de coruptie / infractiuni asimilate coruptiei',
    sentence: formatAutomatedSentence(sentenceMonths, suspended),
    sentence_years: Number((sentenceMonths / 12).toFixed(2)),
    conviction_year: convictionYear,
    status: 'convicted',
    execution_type: suspended ? 'Cu suspendare' : 'Cu executare',
    details:
      `Potrivit datelor DNA indexate in Harta coruptiei, condamnarea definitiva a fost pronuntata la ${convictionDate}. ` +
      `Functia consemnata in sursa de condamnare: ${sourceRole}` +
      (sourceInstitution === 'Nu este cazul' ? '. ' : ` in ${sourceInstitution}. `) +
      'Nu am identificat o afiliere politica pentru functia respectiva, astfel ca inregistrarea este marcata Independent.',
    verified_at: '2026-07-07',
    sources: [
      {
        label: `DNA - hotarare definitiva ${dnaId}`,
        kind: 'official',
        url: `https://www.dna.ro/comunicat.xhtml?id=${dnaId}`,
      },
      {
        ...AUTOMATED_JUN_25_2026_BEC_LOCAL_CANDIDATE_SOURCES.hartaCoruptiei,
        description:
          `Randul CSV pentru ${name} indica judetul ${county}, pedeapsa de ${sentenceMonths} luni ` +
          `si condamnarea din ${convictionDate}.`,
      },
    ],
  }));

